    def execute_where_query(self, collection_name, js_expression):
        collection = self.db[collection_name]
        query = {'$where': js_expression}
        results = list(collection.find(query))
        return results
    
    def execute_complex_query(self, collection_name, query_dict):
        collection = self.db[collection_name]
        results = list(collection.find(query_dict))
        return results
    
    def filter_by_custom_logic(self, collection_name, js_function):
        return self.execute_where_query(collection_name, js_function)
    
    def filter_price_ratio(self, collection_name):
        js_expr = "this.price / this.stock > 5"
        return self.execute_where_query(collection_name, js_expr)
    
    def filter_complex_conditions(self, collection_name):
        js_expr = """
        function() {
            if (this.category === 'Electronics') {
                return this.price > 100 && this.rating >= 4.5;
            } else {
                return this.stock < 50;
            }
        }
        """
        return self.execute_where_query(collection_name, js_expr)
    
    def filter_nested_properties(self, collection_name):
        js_expr = """
        this.specs && 
        ((this.specs.ram && this.specs.ram >= 16) || 
         (this.specs.adjustable && this.specs.adjustable === true))
        """
        return self.execute_where_query(collection_name, js_expr)
    
    def filter_array_conditions(self, collection_name):
        js_expr = """
        this.tags && this.tags.length > 2 && 
        this.tags.some(function(tag) { return tag.includes('professional'); })
        """
        return self.execute_where_query(collection_name, js_expr)
    
    def filter_date_calculations(self, collection_name):
        js_expr = """
        function() {
            var monthDiff = (new Date() - this.created_at) / (1000 * 60 * 60 * 24 * 30);
            return monthDiff < 3 && this.stock > 50;
        }
        """
        return self.execute_where_query(collection_name, js_expr)
    
    def filter_string_operations(self, collection_name):
        js_expr = """
        this.name.toLowerCase().includes('pro') || 
        this.name.split(' ').length > 1
        """
        return self.execute_where_query(collection_name, js_expr)
    
    def filter_mathematical_operations(self, collection_name):
        js_expr = """
        function() {
            var value_score = this.price * this.rating;
            var availability_score = Math.log(this.stock + 1);
            return value_score / availability_score > 200;
        }
        """
        return self.execute_where_query(collection_name, js_expr)
    
    def advanced_aggregate_with_where(self, collection_name):
        collection = self.db[collection_name]
        pipeline = [
            {
                '$match': {
                    '$where': 'this.price > 50'
                }
            },
            {
                '$group': {
                    '_id': '$category',
                    'avg_price': {'$avg': '$price'},
                    'total_stock': {'$sum': '$stock'},
                    'count': {'$sum': 1}
                }
            },
            {
                '$sort': {'avg_price': -1}
            }
        ]
        return list(collection.aggregate(pipeline))
    
    def execute_user_query(self, collection_name, user_js_expression):
        print(f"\nExecuting user-provided JavaScript expression:")
        print(f"Expression: {user_js_expression}")
        return self.execute_where_query(collection_name, user_js_expression)
    
    def safe_execute_query(self, collection_name, js_expression, timeout_ms=5000):
        collection = self.db[collection_name]
        try:
            cursor = collection.find({'$where': js_expression}).max_time_ms(timeout_ms)
            results = list(cursor)
            return {'success': True, 'results': results, 'count': len(results)}
        except Exception as e:
            return {'success': False, 'error': str(e), 'results': []}
    
    def batch_execute_queries(self, collection_name, js_expressions_list):
        results = {}
        for idx, js_expr in enumerate(js_expressions_list):
            query_name = f"query_{idx + 1}"
            results[query_name] = self.safe_execute_query(collection_name, js_expr)
        return results
    
    def print_results(self, results, title="Query Results"):
        print(f"\n{'='*60}")
        print(f"{title}")
        print(f"{'='*60}")
        if isinstance(results, list):
            print(f"Found {len(results)} document(s):")
            for idx, doc in enumerate(results, 1):
                print(f"\nDocument {idx}:")
                doc_copy = doc.copy()
                if '_id' in doc_copy:
                    doc_copy['_id'] = str(doc_copy['_id'])
                if 'created_at' in doc_copy:
                    doc_copy['created_at'] = doc_copy['created_at'].strftime('%Y-%m-%d')
                print(json.dumps(doc_copy, indent=2))
        elif isinstance(results, dict):
            print(json.dumps(results, indent=2, default=str))
        print(f"{'='*60}\n")

